import json
import urllib.request
import urllib.error
import base64


def lambda_handler(event, context):
    """
    Lambda@Edge Viewer Request function that enriches requests by fetching
    additional data from URLs specified in request headers.
    
    Reads URLs from X-Enrich-URL headers (comma-separated for multiple URLs),
    fetches data from those URLs, and adds the enrichment data as additional
    headers before forwarding to origin.
    
    Note: Lambda@Edge does not support layers or external packages,
    so we use urllib.request instead of the requests library.
    """
    request = event['Records'][0]['cf']['request']
    headers = request.get('headers', {})
    
    # Extract enrichment URLs from X-Enrich-URL header
    enrich_urls = _get_enrich_urls(headers)
    
    if not enrich_urls:
        # No enrichment URLs specified, forward request as-is
        return request
    
    enrichment_results = []
    enrichment_errors = []
    
    for i, url in enumerate(enrich_urls):
        url = url.strip()
        if not url:
            continue
        
        # Validate URL scheme for security
        if not _is_valid_url(url):
            enrichment_errors.append({
                'url': url,
                'error': 'Invalid URL scheme. Only http and https are allowed.'
            })
            continue
        
        try:
            result = _fetch_url(url)
            enrichment_results.append({
                'url': url,
                'status': result['status'],
                'data': result['data'],
                'content_type': result.get('content_type', ''),
                'index': i
            })
        except Exception as e:
            enrichment_errors.append({
                'url': url,
                'error': str(e),
                'index': i
            })
    
    # Build enrichment payload
    enrichment_payload = {
        'results': enrichment_results,
        'errors': enrichment_errors,
        'total_urls': len(enrich_urls),
        'successful': len(enrichment_results),
        'failed': len(enrichment_errors)
    }
    
    # Serialize enrichment data and add as header
    # Base64 encode to safely pass in HTTP headers
    enrichment_json = json.dumps(enrichment_payload)
    enrichment_b64 = base64.b64encode(enrichment_json.encode('utf-8')).decode('utf-8')
    
    # Add enrichment data header (Lambda@Edge header format)
    # Split into chunks if necessary (header value limit is ~1,920 bytes for viewer request)
    MAX_HEADER_VALUE_SIZE = 1920
    
    if len(enrichment_b64) <= MAX_HEADER_VALUE_SIZE:
        request['headers']['x-enrichment-data'] = [{
            'key': 'X-Enrichment-Data',
            'value': enrichment_b64
        }]
        request['headers']['x-enrichment-chunks'] = [{
            'key': 'X-Enrichment-Chunks',
            'value': '1'
        }]
    else:
        # Split into multiple header chunks
        chunks = _chunk_string(enrichment_b64, MAX_HEADER_VALUE_SIZE)
        for chunk_idx, chunk in enumerate(chunks):
            header_name = f'x-enrichment-data-{chunk_idx}'
            header_key = f'X-Enrichment-Data-{chunk_idx}'
            request['headers'][header_name] = [{
                'key': header_key,
                'value': chunk
            }]
        request['headers']['x-enrichment-chunks'] = [{
            'key': 'X-Enrichment-Chunks',
            'value': str(len(chunks))
        }]
    
    # Add summary headers for quick access
    request['headers']['x-enrichment-status'] = [{
        'key': 'X-Enrichment-Status',
        'value': 'enriched'
    }]
    request['headers']['x-enrichment-count'] = [{
        'key': 'X-Enrichment-Count',
        'value': str(len(enrichment_results))
    }]
    request['headers']['x-enrichment-errors-count'] = [{
        'key': 'X-Enrichment-Errors-Count',
        'value': str(len(enrichment_errors))
    }]
    
    # Add individual result snippets as separate headers for easy access
    for result in enrichment_results:
        idx = result['index']
        # Truncate data for header-safe snippet
        snippet = result['data'][:500] if result['data'] else ''
        snippet_b64 = base64.b64encode(snippet.encode('utf-8')).decode('utf-8')
        
        header_name = f'x-enrichment-result-{idx}'
        header_key = f'X-Enrichment-Result-{idx}'
        request['headers'][header_name] = [{
            'key': header_key,
            'value': snippet_b64
        }]
    
    # Remove the original X-Enrich-URL header to prevent re-processing
    # or leaking internal enrichment URLs to origin
    if 'x-enrich-url' in headers:
        del request['headers']['x-enrich-url']
    
    return request


def _get_enrich_urls(headers):
    """
    Extract enrichment URLs from request headers.
    Supports comma-separated URLs in a single X-Enrich-URL header
    or multiple X-Enrich-URL-N headers.
    """
    urls = []
    
    # Check for X-Enrich-URL header (comma-separated)
    if 'x-enrich-url' in headers:
        for header_entry in headers['x-enrich-url']:
            value = header_entry.get('value', '')
            urls.extend(value.split(','))
    
    # Also check for numbered headers X-Enrich-URL-0, X-Enrich-URL-1, etc.
    for i in range(10):  # Support up to 10 numbered URL headers
        header_name = f'x-enrich-url-{i}'
        if header_name in headers:
            for header_entry in headers[header_name]:
                value = header_entry.get('value', '')
                if value:
                    urls.append(value)
    
    # Clean up URLs
    urls = [url.strip() for url in urls if url.strip()]
    
    return urls


def _is_valid_url(url):
    """
    Validate that the URL uses an allowed scheme to prevent SSRF attacks
    on internal resources.
    """
    url_lower = url.lower().strip()
    
    # Only allow http and https schemes
    if not (url_lower.startswith('http://') or url_lower.startswith('https://')):
        return False
    
    # Block common internal/private network addresses
    blocked_hosts = [
        '169.254.169.254',  # AWS metadata service
        '127.0.0.1',
        'localhost',
        '0.0.0.0',
        '10.',
        '172.16.',
        '172.17.',
        '172.18.',
        '172.19.',
        '172.20.',
        '172.21.',
        '172.22.',
        '172.23.',
        '172.24.',
        '172.25.',
        '172.26.',
        '172.27.',
        '172.28.',
        '172.29.',
        '172.30.',
        '172.31.',
        '192.168.',
    ]
    
    # Extract host portion from URL
    try:
        from urllib.parse import urlparse
        parsed = urlparse(url)
        host = parsed.hostname or ''
        
        for blocked in blocked_hosts:
            if host.startswith(blocked) or host == blocked.rstrip('.'):
                return False
    except Exception:
        return False
    
    return True


def _fetch_url(url, timeout=2):
    """
    Fetch data from the given URL using urllib.request.
    
    Lambda@Edge has a 5-second timeout for viewer requests,
    so we use a short timeout per request.
    
    Args:
        url: The URL to fetch
        timeout: Request timeout in seconds (default 2s to stay within Lambda@Edge limits)
    
    Returns:
        dict with 'status', 'data', and 'content_type'
    """
    try:
        req = urllib.request.Request(
            url,
            method='GET',
            headers={
                'User-Agent': 'Lambda-Edge-Enrichment/1.0',
                'Accept': 'application/json, text/plain, */*',
                'Accept-Encoding': 'identity',  # Keep it simple at edge
            }
        )
        
        with urllib.request.urlopen(req, timeout=timeout) as response:
            status = response.status
            content_type = response.headers.get('Content-Type', '')
            
            # Read response body with size limit to prevent memory issues
            # Lambda@Edge has 128MB memory limit for viewer request triggers
            MAX_RESPONSE_SIZE = 64 * 1024  # 64KB max per URL response
            data = response.read(MAX_RESPONSE_SIZE)
            
            # Attempt to decode as text
            try:
                data_str = data.decode('utf-8')
            except UnicodeDecodeError:
                # If not UTF-8, base64 encode binary data
                data_str = base64.b64encode(data).decode('ascii')
            
            return {
                'status': status,
                'data': data_str,
                'content_type': content_type
            }
    
    except urllib.error.HTTPError as e:
        return {
            'status': e.code,
            'data': str(e.reason),
            'content_type': ''
        }
    
    except urllib.error.URLError as e:
        raise Exception(f'URL Error fetching {url}: {str(e.reason)}')
    
    except Exception as e:
        raise Exception(f'Error fetching {url}: {str(e)}')


def _chunk_string(s, chunk_size):
    """Split a string into chunks of specified size."""
    return [s[i:i + chunk_size] for i in range(0, len(s), chunk_size)]